$outDir = "c:\Users\Usuario\Documents\VIBE CODING\SMASH PADEL CARD\smash-padel-card\public\pokemon-cards\perfect-order"
$seen = @{}
$client = New-Object System.Net.WebClient

foreach ($card in $cards) {
  $key = "$($card.image)"
  if ($seen.ContainsKey($key)) { continue }
  $seen[$key] = $true

  $ext = "jpg"
  $filename = "$($card.card_number.ToString('000'))-$($card.version)-$($card.id).$ext"
  $dest = Join-Path $outDir $filename

  if (Test-Path $dest) {
    Write-Host "SKIP $filename"
    continue
  }

  try {
    $client.DownloadFile($card.image, $dest)
    Write-Host "OK   $filename"
  } catch {
    Write-Host "FAIL $filename - $_"
  }
}

$client.Dispose()
Write-Host "Done. Files in $outDir"
